      "א. לוֹלָב וַעֲרָבָה - שִׁשָּׁה וְשִׁבְעָה. הַהַלֵּל וְהַשִּׂמְחָה – שְׁמוֹנָה. סֻכָּה וְנִסּוּךְ הַמַּיִם – שִׁבְעָה. וְהֶחָלִיל - חֲמִשָּׁה וְשִׁשָּׁה:",
      "ב. לוֹלָב שִׁבְעָה – כֵּיצַד? יוֹם טוֹב הָרִאשׁוֹן שֶׁלֶּחָג שֶׁחָל לִהְיוֹת בַּשַּׁבָּת, לוֹלָב שִׁבְעָה. וּשְׁאָר כָּל הַיָּמִים - שִׁשָּׁה:",
      "ג. עֲרָבָה שִׁבְעָה – כֵּיצַד? יוֹם שְׁבִיעִי שֶׁלַּעֲרָבָה שֶׁחָל לִהְיוֹת בַּשַּׁבָּת, עֲרָבָה שִׁבְעָה. וּשְׁאָר כָּל הַיָּמִים - שִׁשָּׁה:",
      "ד. מִצְוַת לוֹלָב – כֵּיצַד? יוֹם טוֹב הָרִאשׁוֹן שֶׁלֶּחָג שֶׁחָל לִהְיוֹת בַּשַּׁבָּת, מוֹלִיכִין אֶת לוֹלַבֵּיהֶן לְהַר הַבַּיִת. וְהַחַזָּנִין מְקַבְּלִין מֵהֶן, וְסוֹדְרִין אוֹתָן עַל גַּבֵּי אִצְטְבָא, וְהַזְּקֵנִים מַנִּיחִין אֶת שֶׁלָּהֶן בַּלִּשְׁכָּה... וּכְשֶׁרָּאוּ בֵית דִּין שֶׁבָּאוּ לִידֵי סַכָּנָה - הִתְקִינוּ שֶׁיְּהֶא כָּל אֶחָד וְאֶחָד נוֹטֵל בְּבֵיתוֹ:",
      "ה. מִצְוַת עֲרָבָה – כֵּיצַד? מָקוֹם הָיָה לְמַטָּה מִירוּשָׁלַיִם וְנִקְרָא מוֹצָא. יוֹרְדִין לְשָׁם, וּמְלַקְּטִין מִשָּׁם מֻרְבָּיוֹת שֶׁלַּעֲרָבָה... בְּשָׁעַת פְּטִירָתָן מַה הֵן אוֹמְרִים? 'יוֹפִי לָךְ מִזְבֵּחַ, יוֹפִי לָךְ מִזְבֵּחַ'.",
      "ו. כְּמַעֲשֵׂהוּ בַּחוֹל - כָּךְ מַעֲשֵׂהוּ בַּשַּׁבָּת. אֵלָא שֶׁהָיוּ מְלַקְּטִין אוֹתָן מֵעֶרֶב שַׁבָּת, וּמַנִּיחִים אוֹתָן בְּגִּיגִּיּוֹת שֶׁלְּזָהָב כְּדֵי שֶׁלֹּא יִכְמֹשׁוּ...",
      "ז. מִיָּד הַתִּינוֹקוֹת שׁוֹמְטִין אֶת לוֹלַבֵּיהֶן וְאוֹכְלִין אֶתְּרוֹגֵיהֶן:",
      "ח. הַהַלֵּל וְהַשִּׂמְחָה שְׁמוֹנָה – כֵּיצַד? מְלַמֵּד: שֶׁחַיָּב אָדָם בַּהַלֵּל וּבַשִּׂמְחָה וּבִכְבוֹד יוֹם טוֹב הָאַחֲרוֹן שֶׁלֶּחָג... סֻכָּה שִׁבְעָה – כֵּיצַד? גָּמַר מִלֶּאֱכוֹל, לֹא יַתִּיר סֻכָּתוֹ...",
      "ט. נִיסּוּךְ הַמַּיִם – כֵּיצַד? צְלוֹחִית שֶׁלְּזָהָב מַחְזֶקֶת שְׁלֹשָׁה לוֹגִים, הָיָה מְמַלֵּא מִן הַשִּׁילוֹחַ... שֶׁפַּעַם אַחַת נִסַּךְ אֶחָד עַל גַּבֵּי רַגְלָיו, וּרְגָמוּהוּ כָּל הָעָם בְּאֶתְּרוֹגֵיהֶן:",
